// @ts-check
/**
 * Bundle the SysML standard library into a generated TypeScript module.
 *
 * The browser (Web Worker) build has no filesystem, so the standard
 * library files must be embedded directly into the server bundle. This
 * script walks `sysml.library/`, collects every `.sysml` / `.kerml`
 * file, and emits `server/src/library/bundledLibrary.generated.ts`
 * exporting `BUNDLED_LIBRARY: Record<relativePath, content>`.
 *
 * Run automatically before the production build; the generated file is
 * git-ignored.
 */
import { readdirSync, readFileSync, statSync, writeFileSync } from 'node:fs';
import { dirname, join, relative, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(__dirname, '..');
const libRoot = join(repoRoot, 'sysml.library');
const outFile = join(repoRoot, 'server', 'src', 'library', 'bundledLibrary.generated.ts');

/** @param {string} dir @param {string[]} acc */
function walk(dir, acc) {
    for (const name of readdirSync(dir)) {
        const full = join(dir, name);
        const st = statSync(full);
        if (st.isDirectory()) {
            walk(full, acc);
        } else if (name.endsWith('.sysml') || name.endsWith('.kerml')) {
            acc.push(full);
        }
    }
    return acc;
}

const files = walk(libRoot, []).sort();

/** @type {Record<string, string>} */
const bundle = {};
let totalBytes = 0;
for (const full of files) {
    // Use forward-slash relative paths as stable, platform-independent keys.
    const rel = relative(libRoot, full).split(/[\\/]/).join('/');
    const content = readFileSync(full, 'utf8');
    bundle[rel] = content;
    totalBytes += content.length;
}

const header = `// AUTO-GENERATED by scripts/bundle-library.mjs — DO NOT EDIT.
// Embeds the SysML standard library for the browser (Web Worker) build,
// which has no filesystem. Regenerated by the production build.
/* eslint-disable */

export const BUNDLED_LIBRARY: Record<string, string> = `;

writeFileSync(outFile, header + JSON.stringify(bundle) + ';\n', 'utf8');

console.log(
    `Bundled ${files.length} library files (${(totalBytes / 1024 / 1024).toFixed(2)} MB) → ${relative(repoRoot, outFile)}`,
);
